 82→
 83→function detectChangedFields(
 84→  current: Record<string, unknown>,
 85→  previous: Record<string, unknown>,
 86→): Array<{
 87→  field: string;
 88→  prev: string;
 89→  curr: string;
 90→  magnitude: number | null;
 91→  direction: DeltaDirection;
 92→}> {
 93→  const changes: Array<{
 94→    field: string;
 95→    prev: string;
 96→    curr: string;
 97→    magnitude: number | null;
 98→    direction: DeltaDirection;
 99→  }> = [];
100→
101→  const allKeys = new Set([...Object.keys(current), ...Object.keys(previous)]);
102→  for (const key of allKeys) {
103→    if (SKIP_FIELDS.has(key)) continue;
104→    const cv = current[key];
105→    const pv = previous[key];
106→    const cs = JSON.stringify(cv ?? null);
107→    const ps = JSON.stringify(pv ?? null);
108→    if (cs === ps) continue;
109→
110→    let magnitude: number | null = null;
111→    let direction: DeltaDirection = "not_applicable";
112→    if (typeof cv === "number" && typeof pv === "number") {
113→      magnitude = cv - pv;
114→      direction = cv > pv ? "increase" : cv < pv ? "decrease" : "stable";
115→    }
116→
117→    changes.push({
118→      field: key,
119→      prev: ps,
120→      curr: cs,
121→      magnitude,
122→      direction,
123→    });
124→  }
125→  return changes;
126→}
127→
128→export function computeDeltas(
129→  currentMap: Map<string, ProjectedPoint>,
130→  previousMap: Map<string, ProjectedPoint>,
131→  snapshotDate: string,
132→  baselineDate: string,
133→): DeltaRow[] {
134→  const deltas: DeltaRow[] = [];
135→
136→  // New points
137→  for (const [pointId, point] of currentMap) {
138→    if (!previousMap.has(pointId)) {
139→      deltas.push({
140→        snapshotDate,
141→        baselineSnapshotDate: baselineDate,
142→        verticalId: point.category,
143→        pointId,
144→        deltaType: "new",
145→        deltaField: null,
146→        previousValue: null,
147→        currentValue: null,
148→        deltaMagnitude: null,
149→        deltaDirection: "not_applicable",
150→        deltaSummary: `New ${point.category} point added`,
151→      });
152→    }
153→  }
154→
155→  // Removed points
156→  for (const [pointId, point] of previousMap) {
157→    if (!currentMap.has(pointId)) {
158→      deltas.push({
159→        snapshotDate,
160→        baselineSnapshotDate: baselineDate,
161→        verticalId: point.category,
162→        pointId,
163→        deltaType: "removed",
164→        deltaField: null,
165→        previousValue: null,
166→        currentValue: null,
167→        deltaMagnitude: null,
168→        deltaDirection: "not_applicable",
169→        deltaSummary: `${point.category} point removed`,
170→      });
171→    }
172→  }
173→
174→  // Changed / unchanged
175→  for (const [pointId, current] of currentMap) {
176→    const previous = previousMap.get(pointId);
177→    if (!previous) continue;
178→
179→    const changes = detectChangedFields(
180→      current.details as Record<string, unknown>,
181→      previous.details as Record<string, unknown>,
182→    );
183→
184→    if (changes.length === 0) {
185→      deltas.push({
186→        snapshotDate,
187→        baselineSnapshotDate: baselineDate,
188→        verticalId: current.category,
189→        pointId,
190→        deltaType: "unchanged",
191→        deltaField: null,
192→        previousValue: null,
193→        currentValue: null,
194→        deltaMagnitude: null,
195→        deltaDirection: "stable",
196→        deltaSummary: null,
197→      });
198→    } else {
199→      for (const change of changes) {
200→        const pctStr =
201→          change.magnitude !== null && change.direction !== "not_applicable"
202→            ? ` (${change.direction === "increase" ? "+" : ""}${change.magnitude})`
203→            : "";
204→        deltas.push({
205→          snapshotDate,
206→          baselineSnapshotDate: baselineDate,
207→          verticalId: current.category,
208→          pointId,
209→          deltaType: "changed",
210→          deltaField: change.field,
211→          previousValue: change.prev,
212→          currentValue: change.curr,
213→          deltaMagnitude: change.magnitude,
214→          deltaDirection: change.direction,
215→          deltaSummary: `${change.field} changed: ${change.prev} → ${change.curr}${pctStr}`,
216→        });
217→      }
218→    }
219→  }
220→
221→  return deltas;
222→}
