 11→function normalizeUserId(input: string): string {
 12→  return input.toLowerCase().trim();
 13→}
 14→
 15→function normalizeMapScope(input: unknown): MapScope {
 16→  if (typeof input !== "string") return "bonamoussadi";
 17→  const normalized = input.trim().toLowerCase() as MapScope;
 18→  if (!VALID_MAP_SCOPES.has(normalized)) return "bonamoussadi";
 19→  return normalized;
 20→}
