 22→function parseXp(input: unknown): number {
 23→  const value = typeof input === "number" ? input : Number(input);
 24→  if (!Number.isFinite(value)) return 0;
 25→  return Math.max(0, Math.round(value));
 26→}
 27→
 28→function isUuid(input: string): boolean {
 29→  return /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(input);
 30→}
 31→
 32→function deterministicUuid(seed: string): string {
 33→  const hex = createHash("sha1").update(seed).digest("hex").slice(0, 32).split("");
 34→  hex[12] = "5";
 35→  const variant = parseInt(hex[16], 16);
 36→  hex[16] = ((variant & 0x3) | 0x8).toString(16);
 37→  return `${hex.slice(0, 8).join("")}-${hex.slice(8, 12).join("")}-${hex.slice(12, 16).join("")}-${hex.slice(16, 20).join("")}-${hex.slice(20, 32).join("")}`;
 38→}
 39→
 40→function normalizeEventId(input: string): string {
 41→  const trimmed = input.trim();
 42→  if (isUuid(trimmed)) return trimmed.toLowerCase();
 43→  return deterministicUuid(`event:${trimmed}`);
 44→}
 45→
 46→function normalizeCreatedAt(input: unknown): string {
 47→  if (typeof input === "string") {
 48→    const parsed = new Date(input);
 49→    if (!Number.isNaN(parsed.getTime())) return parsed.toISOString();
 50→  }
 51→  return new Date().toISOString();
 52→}
 53→
 54→function parseCategory(input: unknown): SubmissionCategory {
 55→  if (typeof input === "string" && isValidCategory(input)) return input as SubmissionCategory;
 56→  return "mobile_money";
 57→}
 58→
 59→function parseEventType(input: unknown): PointEventType {
 60→  if (input === "CREATE_EVENT" || input === "ENRICH_EVENT") return input;
 61→  return "CREATE_EVENT";
 62→}
 63→
 64→function parseLocation(input: unknown): { latitude: number; longitude: number } | null {
 65→  const raw = input as { latitude?: unknown; longitude?: unknown };
 66→  const latitude = typeof raw?.latitude === "number" ? raw.latitude : Number(raw?.latitude);
 67→  const longitude = typeof raw?.longitude === "number" ? raw.longitude : Number(raw?.longitude);
 68→  if (!Number.isFinite(latitude) || !Number.isFinite(longitude)) return null;
 69→  return { latitude, longitude };
 70→}
