 72→function rowToUserProfile(row: Record<string, unknown>): UserProfile {
 73→  const email = typeof row.email === "string" && row.email.trim() ? row.email.toLowerCase().trim() : null;
 74→  const phone = typeof row.phone === "string" && row.phone.trim() ? row.phone.trim() : null;
 75→  return {
 76→    id: String(row.id ?? "").toLowerCase().trim(),
 77→    email,
 78→    phone,
 79→    name: typeof row.name === "string" ? row.name : "",
 80→    image: typeof row.image === "string" ? row.image : "",
 81→    occupation: typeof row.occupation === "string" ? row.occupation : "",
 82→    XP: parseXp(row.xp),
 83→    passwordHash: typeof row.password_hash === "string" ? row.password_hash : undefined,
 84→    isAdmin: Boolean(row.is_admin),
 85→    mapScope: normalizeMapScope(row.map_scope),
 86→  };
 87→}
