 89→function isMissingPhoneColumnError(error: unknown): boolean {
 90→  if (!(error instanceof Error)) return false;
 91→  const pgError = error as Error & { code?: string };
 92→  const message = error.message.toLowerCase();
 93→  return pgError.code === "42703" && message.includes("phone");
 94→}
