133→async function getUserProfile(userId: string): Promise<UserProfile | null> {
134→  const id = normalizeUserId(userId);
135→  if (phoneColumnState === "missing") {
136→    return await getUserProfileLegacy(id);
137→  }
138→
139→  try {
140→    const result = await query<Record<string, unknown>>(
141→      `
142→        select id, email, phone, name, image, occupation, xp, password_hash, is_admin, map_scope
143→        from user_profiles
144→        where id = $1
145→        limit 1
146→      `,
147→      [id],
148→    );
149→
150→    const row = result.rows[0];
151→    if (!row) return null;
152→    if (phoneColumnState === "unknown") phoneColumnState = "present";
153→    return rowToUserProfile(row);
154→  } catch (error) {
155→    if (!isMissingPhoneColumnError(error)) throw error;
156→    phoneColumnState = "missing";
157→    return await getUserProfileLegacy(id);
158→  }
159→}
